import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const DashboardPage = ({ user }) => {
  const [scores, setScores] = useState([]);
  const [value, setValue] = useState('');
  const [date, setDate] = useState('');
  const [message, setMessage] = useState('');
  const [profile, setProfile] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    if (!user) { navigate('/login'); return; }
    fetchScores();
    fetchProfile();
  }, [user]);

  const fetchProfile = async () => {
    try {
      const { data } = await axios.get('/auth/me');
      setProfile(data);
    } catch (err) {
      setMessage('Unable to fetch profile');
    }
  };

  const fetchScores = async () => {
    try {
      const { data } = await axios.get('/scores');
      setScores(data);
    } catch (err) {
      setMessage('Unable to fetch scores');
    }
  };

  const addScore = async (e) => {
    e.preventDefault();
    try {
      const { data } = await axios.post('/scores', { value: Number(value), date });
      setScores(data);
      setValue('');
      setDate('');
      setMessage('Score saved');
    } catch (err) {
      setMessage(err.response?.data?.message || 'Error adding score');
    }
  };

  if (!user) return null;

  return (
    <div style={{maxWidth:'800px', margin:'0 auto', padding:'20px'}}>
      <h2>User Dashboard</h2>
      {profile && (
        <div style={{marginBottom:'20px'}}>
          <p><strong>Name:</strong> {profile.name}</p>
          <p><strong>Email:</strong> {profile.email}</p>
          <p><strong>Role:</strong> {profile.role}</p>
          <p><strong>Subscription:</strong> {profile.subscription?.status || 'Inactive'}</p>
          <p><strong>Charity Contribution:</strong> {profile.charityContributionPercent}%</p>
          <p><strong>Total Won:</strong> ${profile.winningsSummary?.totalWon || 0}</p>
        </div>
      )}
      <section style={{marginBottom:'20px'}}>
        <h3>Score Entry (Stableford 1-45)</h3>
        <form onSubmit={addScore} style={{display:'flex', gap:'10px', marginBottom:'10px'}}>
          <input type='number' value={value} onChange={(e) => setValue(e.target.value)} min='1' max='45' placeholder='Score' required style={{flex:1}} />
          <input type='date' value={date} onChange={(e) => setDate(e.target.value)} required style={{flex:1}} />
          <button type='submit'>Add Score</button>
        </form>
        {message && <p>{message}</p>}
        <ul>
          {scores.map((s) => <li key={s._id}>{new Date(s.date).toLocaleDateString()} - {s.value}</li>)}
        </ul>
      </section>
    </div>
  );
};

export default DashboardPage;
